// Vault KV path: secret/data/payment-service
// Spring Cloud Vault maps Vault keys → Spring properties:
// Vault: { 'visa_api_key': 'rzp_live_...', 'redis_password': '...' }
// Spring: payment.visa.api-key = rzp_live_...

@Service
class VaultSecretService {
    @Value("${payment.visa.api-key:test-key}")
    private String visaApiKey;

    @Value("${spring.datasource.username:sa}")
    private String dbUser;  // injected from Vault dynamic secret

    @Value("${spring.datasource.password:password}")
    private String dbPassword;  // injected from Vault dynamic secret

    boolean hasApiKey() { return visaApiKey != null && !visaApiKey.isBlank(); }
    String getMaskedUser() { return dbUser.substring(0, Math.min(6, dbUser.length())) + "***"; }
}

// POD RESTART:
// - Old dynamic credentials expire (1h TTL)
// - New pod starts, authenticates to Vault
// - Vault generates NEW unique DB username/password
// - HikariCP uses the new credentials
// - Old username no longer exists in PostgreSQL

@SpringBootTest
@TestPropertySource(properties={"payment.visa.api-key=test-visa-key","spring.datasource.username=test-user"})
class VaultValueTest {
    @Autowired VaultSecretService svc;
    @Test void secretValues_injected(){
        assertTrue(svc.hasApiKey());
        assertTrue(svc.getMaskedUser().startsWith("test-u"));
    }
}

import org.springframework.vault.core.VaultTemplate;
import org.springframework.stereotype.*;
import org.springframework.vault.support.VaultResponse;
import java.util.*;

@Service
public class VaultConfigLoader {
    private final VaultTemplate vault;
    VaultConfigLoader(VaultTemplate v) { vault = v; }

    // READ secret from KV v2:
    @SuppressWarnings("unchecked")
    public Map<String,Object> readSecret(String path) {
        // KV v2: path is 'secret/data/payment-service' internally
        VaultResponse response = vault.read("secret/data/" + path);
        if (response == null) return Map.of();
        Map<String,Object> data = (Map<String,Object>) response.getData().get("data");
        return data != null ? data : Map.of();
    }

    // WRITE secret (for rotation — called by ops tooling):
    public void writeSecret(String path, Map<String,Object> values) {
        vault.write("secret/data/" + path, Map.of("data", values));
    }

    // CHECK if path exists:
    public boolean exists(String path) {
        return vault.read("secret/data/" + path) != null;
    }

    // VaultTemplate vs @Value:
    // @Value: best for secrets known at startup (API keys, passwords)
    //         simple, auto-injected by Spring Cloud Vault, no code needed
    // VaultTemplate: needed when:
    //   - Path is dynamic (per-user secrets, per-merchant config)
    //   - Need to write secrets (rotation automation)
    //   - Reading at runtime after startup (not available at boot time)
    //   - Checking existence before reading
    public static void main(String[] a){
        System.out.println("@Value: static secrets. VaultTemplate: dynamic paths, write access");
    }
}

