// ZERO-DOWNTIME SECRET ROTATION WITH VAULT DYNAMIC SECRETS:
//
// STATIC PASSWORD ROTATION (hard):
//   Step 1: Update password in PostgreSQL
//   Step 2: Update all 10 service instances simultaneously
//   Risk: brief window where old password still in use → 401 errors
//   Solution: rolling restart with compatible both-password period
//
// VAULT DYNAMIC SECRETS (automatic):
//   Each pod gets UNIQUE credentials:
//     pod-a: username=v-k8s-pay-abc123, password=x, TTL=1h
//     pod-b: username=v-k8s-pay-def456, password=y, TTL=1h
//   Rotation = new pods get new credentials automatically
//   Old pods: their credentials expire after TTL
//   'Rotation': just restart pods → each gets fresh dynamic credential
//   PostgreSQL: multiple valid users at once (old + new) during rolling restart
//   No coordination needed!

@Service
class SecretRotationStrategy {
    enum RotationType { DYNAMIC_VAULT, STATIC_WITH_DUAL_WRITE, MANUAL }

    RotationType strategyFor(String secretType) {
        return switch(secretType) {
            case "database_password" -> RotationType.DYNAMIC_VAULT;  // best
            case "api_key" -> RotationType.STATIC_WITH_DUAL_WRITE;  // add new, deprecate old
            case "tls_certificate" -> RotationType.DYNAMIC_VAULT;  // Vault PKI engine
            default -> RotationType.MANUAL;
        };
    }
}

@SpringBootTest
class SecretRotationTest {
    @Autowired SecretRotationStrategy strategy;
    @Test void dbPassword_usesDynamicVault(){
        assertEquals(SecretRotationStrategy.RotationType.DYNAMIC_VAULT, strategy.strategyFor("database_password"));
    }
}

# vault/policies/payment-service.hcl
path "secret/data/payment-service" {
  capabilities = ["read"]
  # Read-only: API keys, Redis password, Visa credentials
  # Cannot write (prevents compromised service from modifying its own secrets)
}

path "secret/data/payment-service/*" {
  capabilities = ["read"]
  # Also allow reading sub-paths (e.g., secret/data/payment-service/prod)
}

path "database/creds/payment-service-db" {
  capabilities = ["read"]
  # Allows requesting dynamic DB credentials
  # Vault generates unique username/password on each read
}

path "sys/leases/renew" {
  capabilities = ["update"]
  # Allows Spring Cloud Vault to renew leases before expiry
}

path "auth/token/renew-self" {
  capabilities = ["update"]
  # Allows service to renew its own auth token
}

# ALL OTHER PATHS: implicitly denied
# payment-service cannot read other services' secrets
# Cannot read infrastructure secrets
# Cannot write to any path (read-only)

# WHY LEAST PRIVILEGE:
# Compromised payment-service pod:
#   With least privilege: can only read payment-service secrets (1h TTL)
#   Without: could read ALL secrets, write new secrets, impersonate other services

# Apply policy:
# vault policy write payment-service vault/policies/payment-service.hcl
# vault write auth/kubernetes/role/payment-service \
#   bound_service_account_names=payment-service \
#   bound_service_account_namespaces=payments \
#   policies=payment-service \
#   ttl=1h

public class VaultPolicyDoc { public static void main(String[] a){
    System.out.println("Vault policy: least privilege per service");
} }

import org.springframework.vault.core.VaultTemplate;
import org.springframework.stereotype.*;
import org.springframework.scheduling.annotation.Scheduled;
import org.slf4j.*;
import java.util.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
public class SecretAuditService {
    private static final Logger log = LoggerFactory.getLogger(SecretAuditService.class);
    private final VaultTemplate vault;
    SecretAuditService(VaultTemplate v) { vault = v; }

    @Scheduled(fixedRate = 300_000)  // every 5 min
    public void auditLeases() {
        try {
            // List active leases for this service's DB credentials:
            var leaseListResponse = vault.read("sys/leases/lookup");
            if (leaseListResponse != null && leaseListResponse.getData() != null) {
                log.info("[SECRET AUDIT] Vault lease check: {}", leaseListResponse.getData());
            }
            log.info("[SECRET AUDIT] All leases verified: {}", new Date());
        } catch (Exception e) {
            // Vault unreachable: alert!
            log.error("[SECRET AUDIT] Cannot reach Vault — secret rotation may fail!", e);
        }
    }

    public void logSecretAccess(String path, String operation) {
        // Vault audit log captures this automatically, but application-level log helps:
        log.info("[SECRET ACCESS] path={} op={} time={}", path, operation, new Date());
        // NEVER log the actual secret value — only the path and operation
    }
}

@SpringBootTest
class SecretAuditTest {
    @Autowired SecretAuditService svc;
    @Test void auditService_instantiates() {
        assertNotNull(svc);
        // Verify no secret values are logged (only path+operation)
        svc.logSecretAccess("secret/payment-service", "read");
    }
}

