@Service
class FullVaultSecretService {
    @Value("${payment.visa.api-key:test-visa-key}")
    private String visaApiKey;

    private final VaultTemplate vault;
    FullVaultSecretService(VaultTemplate v){vault=v;}

    boolean hasVisaKey(){ return visaApiKey!=null&&!visaApiKey.isBlank(); }
    String visaKeyPrefix(){ return visaApiKey.substring(0,Math.min(4,visaApiKey.length())); }

    // Dynamic: get secret for specific merchant (path varies at runtime)
    @SuppressWarnings("unchecked")
    Map<String,Object> getMerchantSecret(String merchantId){
        try{
            var r=vault.read("secret/data/merchants/"+merchantId);
            if(r!=null&&r.getData()!=null) return (Map<String,Object>)r.getData().getOrDefault("data",Map.of());
        }catch(Exception e){/* Vault not available in test */}
