    // Audit log: path and time only (NEVER the value)
    List<String> auditLog = new java.util.ArrayList<>();
    void logAccess(String path){ auditLog.add("ACCESS path="+path+" time="+new Date().toInstant()); }
    List<String> getAuditLog(){ return Collections.unmodifiableList(auditLog); }
}

