// VAULT PKI ENGINE:
// Manages certificate authority (CA) and issues short-lived certificates
// Much better than: self-signed certs in k8s Secrets (manual rotation!)

// Vault setup (ops team does this once):
// vault secrets enable pki
// vault write pki/root/generate/internal common_name='razorpay.internal' ttl='87600h'
// vault write pki/roles/payment-service \
//   allowed_domains='payments.svc.cluster.local' \
//   allow_subdomains=true \
//   max_ttl='24h'

// Spring Boot: spring-cloud-vault-config-databases approach for PKI:
// spring.cloud.vault.pki.enabled=true
// spring.cloud.vault.pki.role=payment-service
// spring.cloud.vault.pki.backend=pki
// spring.cloud.vault.pki.cn=payment-service.payments.svc.cluster.local

// Spring Cloud Vault then:
// 1. Requests certificate from Vault PKI (24h TTL)
// 2. Writes cert + key to local files
// 3. Configures server.ssl.key-store pointing to the Vault-issued cert
// 4. At 80% TTL: requests new cert, hot-reloads SSL context

// mTLS (mutual TLS):
// Normal TLS: server presents certificate, client verifies
// mTLS: BOTH server AND client present certificates
// Use for: payment-service → fraud-service (both verify each other)
// No JWT needed for authentication — the TLS cert IS the identity!
// Vault PKI issues certs for both sides:
// payment-service cert: CN=payment-service.payments.svc.cluster.local
// fraud-service cert: CN=fraud-service.payments.svc.cluster.local
// Each service's TrustStore includes Vault's CA (trusts all Vault-issued certs)

public class VaultPKIGuide { public static void main(String[] a){
    System.out.println("Vault PKI: auto-managed TLS certs with 24h TTL and mTLS support");
} }

