// bootstrap.yml retry config:
// spring.cloud.vault.fail-fast: false  # don't fail startup if Vault unavailable
// spring.cloud.vault.config.lifecycle:
//   enabled: true
//   min-renewal: 10s
//   expiry-threshold: 1m  # renew when 1 min remaining
// spring.retry:
//   max-attempts: 5
//   initial-interval: 1000  # 1s initial retry
//   multiplier: 2.0         # exponential backoff
//   max-interval: 30000     # max 30s between retries

@Service
class VaultResilienceService {
    private static final Logger log = LoggerFactory.getLogger(VaultResilienceService.class);
    private final VaultTemplate vault;
    // Fallback values from k8s Secret (set at startup from env vars):
    @Value("${payment.visa.api-key.fallback:}") private String fallbackVisaKey;
    boolean vaultHealthy = true;

    VaultResilienceService(VaultTemplate v){vault=v;}

    public String getVisaKey() {
        if (!vaultHealthy && !fallbackVisaKey.isBlank()) {
            log.warn("[VAULT] Using fallback credentials — Vault unavailable");
            return fallbackVisaKey;
        }
        try {
            var r = vault.read("secret/data/payment-service");
            if (r != null) return (String)((java.util.Map<?,?>)r.getData().get("data")).get("visa_api_key");
        } catch (Exception e) {
            log.error("[VAULT] Cannot read secret: {}", e.getMessage());
            vaultHealthy = false;
        }
        return fallbackVisaKey;
    }

    @Scheduled(fixedRate=30_000)
    public void checkVaultHealth(){
        try { vault.read("sys/health"); vaultHealthy=true; }
        catch(Exception e){ vaultHealthy=false; log.error("[VAULT] Health check failed"); }
    }
}

@SpringBootTest
class VaultResilienceTest {
    @Autowired VaultResilienceService svc;
    @Test void fallback_activatesWhenVaultDown(){
        svc.vaultHealthy=false;
        // With fallback value empty: returns empty string (safe)
        String key=svc.getVisaKey();
        assertNotNull(key); // returns fallback (empty or configured)
    }
}

