@Service class SynthVaultService {
    @Value("${payment.visa.api-key:test-key-default}") String visaKey;
    boolean hasKey(){return visaKey!=null&&!visaKey.isBlank();}
    String type(){return visaKey.startsWith("rzp_")?"live":"test";}
}

@Service class SynthAuditService {
    private final List<String> log=new ArrayList<>();
    void access(String path){log.add("READ:"+path+"::"+new Date().toInstant());}
    boolean valuesNeverLogged(String secretValue){
        return log.stream().noneMatch(e->e.contains(secretValue));
    }
}

@Service class SynthFallbackService {
    private final VaultTemplate vault;
    boolean usesFallback=false;
    SynthFallbackService(VaultTemplate v){vault=v;}
    String getKeyWithFallback(String fallback){
        try{
            vault.read("secret/data/test");
            return "vault-value";
        }catch(Exception e){
            usesFallback=true;
            return fallback;
        }
    }
}

@SpringBootTest
@TestPropertySource(properties={"payment.visa.api-key=rzp_test_synth_key"})
class M23T3SynthesisTest {
    @Autowired SynthVaultService vault;
    @Autowired SynthAuditService audit;
    @Autowired SynthFallbackService fallback;

    @Test void visaKey_injected(){
        assertTrue(vault.hasKey());
        assertEquals("live",vault.type());  // starts with rzp_ → live
    }
    @Test void auditLog_noSecretValues(){
        audit.access("secret/payment-service");
        assertTrue(audit.valuesNeverLogged("rzp_test_synth_key"),"Secret value must not appear in audit log");
    }
    @Test void fallback_whenVaultUnavailable(){
        String result=fallback.getKeyWithFallback("emergency-fallback");
        // VaultTemplate in test: will fail → fallback activates
        assertNotNull(result);
    }
}
